select.if:
WITH RECURSIVE category_tree AS ( SELECT id FROM gb_categories WHERE del_flag = '0' AND POSITION(CAST(id AS CHAR) IN #{categoryIdsFilter}) > 0 > 0 UNION ALL SELECT c.id FROM gb_categories c INNER JOIN category_tree ct ON c.parent_id = ct.id WHERE c.del_flag = '0' )
SELECT g.*, coalesce(box_cnt.cnt, 0) as box_count, box_cnt.box_ids as box_ids, coalesce(site_cnt.incl_cnt, 0) as related_sites_count, coalesce(site_cnt.excl_cnt, 0) as excluded_sites_count, c.name as category_name, c.icon as category_icon, -- 统一的可见性状态： -- 1. 自有游戏（site_id = 当前网站）：使用游戏本身的status -- 2. 默认配置（site_id = 0）： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站游戏：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN g.site_id = #{siteId} THEN g.status WHEN g.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE coalesce(incl.is_visible, '0') END as is_visible, -- 关联来源标识 CASE WHEN g.site_id = #{siteId} THEN 'own' WHEN g.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN g.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN '1' ELSE '0' END as is_excluded FROM gb_games g -- 通过关联表获取主分类信息 LEFT JOIN gb_game_category_relations gcr ON g.id = gcr.game_id AND gcr.is_primary = '1' LEFT JOIN gb_categories c ON gcr.category_id = c.id AND c.del_flag = '0' -- 左连接正向关联（include） LEFT JOIN gb_site_game_relations incl ON g.id = incl.game_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_game_relations excl ON g.id = excl.game_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude' -- 预聚合：盒子数量（仅统计当前站点可见的盒子：自有+默认未排除+共享已关联） LEFT JOIN ( SELECT bgr.game_id, COUNT(*) as cnt, GROUP_CONCAT(bgr.box_id ORDER BY bgr.sort_order ASC SEPARATOR ',') as box_ids FROM gb_box_game_relations bgr INNER JOIN gb_game_boxes b ON bgr.box_id = b.id AND b.del_flag = '0' LEFT JOIN gb_site_box_relations box_incl ON b.id = box_incl.box_id AND box_incl.site_id = #{siteId} AND box_incl.relation_type = 'include' LEFT JOIN gb_site_box_relations box_excl ON b.id = box_excl.box_id AND box_excl.site_id = #{siteId} AND box_excl.relation_type = 'exclude' WHERE ( b.site_id = #{siteId} OR (b.site_id = #{params.personalSiteId} AND NOT (box_incl.id IS NULL AND box_excl.id IS NOT NULL)) OR (b.site_id != #{siteId} AND b.site_id != #{params.personalSiteId} AND box_incl.id IS NOT NULL) ) GROUP BY bgr.game_id ) box_cnt ON g.id = box_cnt.game_id -- 预聚合：关联/排除站点数量（避免N+1关联子查询） LEFT JOIN ( SELECT game_id, SUM(CASE WHEN relation_type = 'include' THEN 1 ELSE 0 END) as incl_cnt, SUM(CASE WHEN relation_type = 'exclude' THEN 1 ELSE 0 END) as excl_cnt FROM gb_site_game_relations GROUP BY game_id ) site_cnt ON g.id = site_cnt.game_id
g.del_flag = '0'
AND ( g.site_id = #{siteId}
OR g.site_id = #{params.personalSiteId}
OR (g.site_id != #{siteId}
AND g.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) AND g.name LIKE concat('%', #{name}, '%') AND g.subtitle LIKE concat('%', #{subtitle}, '%')
AND EXISTS ( SELECT 1 FROM gb_game_category_relations gcr WHERE gcr.game_id = g.id AND gcr.category_id IN (SELECT id FROM category_tree) )
AND NOT EXISTS ( SELECT 1 FROM gb_game_category_relations gcr_unc WHERE gcr_unc.game_id = g.id )
AND (g.game_type IS NULL OR g.game_type = '')
AND g.game_type = #{gameType}
AND g.device_support = #{deviceSupport} AND g.is_new = #{isNew} AND g.is_hot = #{isHot} AND g.is_recommend = #{isRecommend}
AND ( (g.site_id = #{siteId} AND g.status = #{status}) OR (g.site_id = #{params.personalSiteId} AND ( CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END ) = #{status}) OR (g.site_id != #{siteId} AND g.site_id != #{params.personalSiteId} AND coalesce(incl.is_visible, '0') = #{status}) )
AND EXISTS ( SELECT 1 FROM gb_box_game_relations bgr WHERE bgr.game_id = g.id AND POSITION(CAST(bgr.box_id AS CHAR) IN #{boxIdsFilter}) > 0 > 0 )
AND g.update_time >= FROM_UNIXTIME(#{updateTimeStart}/1000)
AND g.update_time <= DATE_ADD(FROM_UNIXTIME(#{updateTimeEnd}/1000), INTERVAL 1 DAY)
ORDER BY coalesce(box_cnt.cnt, 0) DESC, g.sort_order ASC, g.create_time DESC

