site_id = #{siteId}, name = #{name}, subtitle = #{subtitle}, short_name = #{shortName}, game_type = #{gameType}, icon_url = #{iconUrl}, cover_url = #{coverUrl}, banner_url = #{bannerUrl}, screenshots = #{screenshots}, video_url = #{videoUrl}, description = #{description}, promotion_desc = #{promotionDesc}, developer = #{developer}, publisher = #{publisher}, package_name = #{packageName}, version = #{version}, size = #{size}, device_support = #{deviceSupport}, download_count = #{downloadCount}, rating = #{rating}, features = #{features}, tags = #{tags}, launch_time = #{launchTime}, is_new = #{isNew}, is_hot = #{isHot}, is_recommend = #{isRecommend}, sort_order = #{sortOrder}, status = #{status}, del_flag = #{delFlag}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark}, download_url = #{downloadUrl}, android_url = #{androidUrl}, ios_url = #{iosUrl}, apk_url = #{apkUrl}, discount_label = #{discountLabel}, first_charge_domestic = #{firstChargeDomestic}, first_charge_overseas = #{firstChargeOverseas}, recharge_domestic = #{rechargeDomestic}, recharge_overseas = #{rechargeOverseas}, has_support = #{hasSupport}, support_desc = #{supportDesc}, has_low_deduct_coupon = #{hasLowDeductCoupon}, low_deduct_coupon_url = #{lowDeductCouponUrl}, source_box_id = #{sourceBoxId},
